const body = $input.item.json.body || {};
const master = $env.MARY_MASTER_TOKEN || '';
if (!body.master_token || body.master_token !== master) return { json: { _unauthorized: true, status: 401 } };
if (!body.event_type) return { json: { _empty: true, status: 400, error: 'event_type required' } };
const severity = body.severity || 'info';
if (['info','warning','critical'].indexOf(severity) === -1) return { json: { _empty: true, status: 400, error: 'severity must be info|warning|critical' } };
return { json: {
  p_event_type:  body.event_type,
  p_severity:    severity,
  p_user_id:     body.user_id     || null,
  p_user_email:  body.user_email  || null,
  p_source_ip:   body.source_ip   || ($input.item.json.headers && ($input.item.json.headers['x-forwarded-for'] || $input.item.json.headers['x-real-ip'])) || null,
  p_user_agent:  body.user_agent  || ($input.item.json.headers && $input.item.json.headers['user-agent']) || null,
  p_endpoint:    body.endpoint    || null,
  p_details:     body.details     || {}
} };

const ret = $input.item.json;
const id = (typeof ret === 'string') ? ret : (ret && ret.id ? ret.id : null);
return { json: { ok: true, event_id: id } };
